public static void main(String[] args) throws Exception {

    // Instantiate a Twitter client
    Twitter twitter = new TwitterFactory().getInstance();

    // Authenticate the client
    twitter.setOAuthConsumer(consumerKey, consumerSecret);
    twitter.setOAuthAccessToken(new AccessToken(accessToken, accessSecret));

    // Create a list of usernames
    List<String> usernames = Arrays.asList("username1", "username2",...);

    // Loop through each username
    for (String username : usernames) {

        // Create a new Twitter account
        User user = new User();
        user.setUsername(username);
        user = twitter.createUser(user);

        // Get the latest tweets from the created account
        ResponseList<Status> statuses = twitter.getUserTimeline(user);

        // Save the scraped data into a file
        FileOutputStream fos = new FileOutputStream("data/" + username + ".txt");
        ObjectOutputStream oos = new ObjectOutputStream(fos);
        oos.writeObject(statuses);
        oos.close();
    }
